+        })))
+        .mount(&server)
+        .await;
+
+    let c = setup_connector(&server.uri()).await;
+    let result = c
+        .handle_invoke(json!({
+            "operation_id": "spotify.show.episodes",
+            "input": {"show_id": "5CfCWKI5pZ28U0uOzXkDHe", "limit": 20, "offset": 0}
